// Returns word unchanged if already singular, unknown, an acronym, or inflect unavailable.
func _singularize(word string, exceptions map[string]struct{}) string {
	if len(word) == 0 {
		return word
	}
	if _isAcronym(word) {
		return word
	}
	lower := strings.ToLower(word)
	if _, ok := exceptions[lower]; ok {
		return word
	}
	engine, err := _getEngine()
	if err != nil {
		// inflect unavailable
		return word
	}
	result, isSingular := engine.SingularNoun(word)
	if !isSingular {
		return word
	}
	if len(result) == 0 {
		return word
	}
	if len(word) > 0 && word[0] >= 'A' && word[0] <= 'Z' && !_isAcronym(word) {
		return strings.Title(strings.ToLower(result))
	}
	return result
}

var _camelBoundary = regexp.MustCompile(`[a-z0-9][A-Z]|[A-Z][A-Z][a-z]`)

// _splitTokens splits text into tokens and returns (tokens, separator).
// Space-separated -> sep=" ", underscore -> sep="_", CamelCase -> sep="".
func _splitTokens(text string) ([]string, string) {
	if strings.Contains(text, " ") {
		return strings.Split(text, " "), " "
	}
	if strings.Contains(text, "_") {
		return strings.Split(text, "_"), "_"
	}
	// CamelCase: split on boundaries
	parts := _camelBoundary.Split(text, -1)
	if len(parts) > 1 {
		return parts, ""
	}
	return []string{text}, ""
}

var (
	_leadingTrailingSymbols = regexp.MustCompile(`(?i)^[^\w\s]+|[^\w\s]+$`)
	_multiSpace             = regexp.MustCompile(`\s+`)
	_dottedAcronym          = regexp.MustCompile(`^([A-Z0-9]\.){2,}[A-Z0-9]?\.?$`)
	_dotReplace             = regexp.MustCompile(`\.`)
)

// normalizeEntity returns the canonical display form of entity.
func normalizeEntity(entity string, exceptions map[string]struct{}) string {
	if len(entity) == 0 {
		return ""
	}
	entity = strings.TrimSpace(entity)
	entity = _leadingTrailingSymbols.ReplaceAllString(entity, "")
	entity = strings.TrimSpace(entity)

	// Collapse dotted acronyms: U.S.A. -> USA
	rawToks := strings.Split(entity, " ")
	collapsed := make([]string, 0, len(rawToks))
	for _, tok := range rawToks {
		candidate := tok
		if !strings.HasSuffix(tok, ".") {
			candidate = tok + "."
		}
		if _dottedAcronym.MatchString(candidate) {
			tok = _dotReplace.ReplaceAllString(tok, "")
		}
		collapsed = append(collapsed, tok)
	}
	entity = strings.Join(collapsed, " ")
	entity = _multiSpace.ReplaceAllString(entity, " ")

	if len(entity) == 0 {
		return ""
	}
	tokens, sep := _splitTokens(entity)
	filtered := make([]string, 0, len(tokens))
	for _, t := range tokens {
		if len(t) > 0 {
			filtered = append(filtered, t)
		}
	}
	if len(filtered) == 0 {
		return ""
	}
	filtered[len(filtered)-1] = _singularize(filtered[len(filtered)-1], exceptions)
	return strings.Join(filtered, sep)
}

