type SpacyMatcher struct {
	nlp          SpacyNLP // interface wrapping spacy language model
	types        map[string]struct{}
	stripNumeric bool
}

// SpacyMatcherOptions holds optional parameters for NewSpacyMatcher.
type SpacyMatcherOptions struct {
	Model        string
	EntityTypes  []string // nil means all labels
	StripNumeric bool
}

// NewSpacyMatcher constructs a SpacyMatcher, loading the spaCy model.
// Returns an error if spaCy is unavailable or the model cannot be loaded.
func NewSpacyMatcher(opts SpacyMatcherOptions) (*SpacyMatcher, error) {
	if opts.Model == "" {
		opts.Model = "en_core_web_sm"
	}
	nlp, err := LoadSpacyModel(opts.Model)
	if err != nil {
		return nil, fmt.Errorf("SpacyMatcher: spaCy unavailable or model not found: %w", err)
	}
	labels := opts.EntityTypes
	if labels == nil {
		labels = AllSpacyLabels()
	}
	types := make(map[string]struct{}, len(labels))
	for _, t := range labels {
		types[t] = struct{}{}
	}
	return &SpacyMatcher{
		nlp:          nlp,
		types:        types,
		stripNumeric: opts.StripNumeric,
	}, nil
}

