// Match runs spaCy NER on text and returns entity matches.
// Multiple occurrences of the same surface form are grouped under one EntityMatch.
func (m *SpacyMatcher) Match(text string) ([]EntityMatch, error) {
	doc, err := m.nlp.Process(text)
	if err != nil {
		return nil, fmt.Errorf("SpacyMatcher.Match: %w", err)
	}

	found := make(map[string]*entryData)

	for _, ent := range doc.Ents() {
		if _, ok := m.types[ent.Label()]; !ok {
			continue
		}
		// Skip stop-word-only spans
		allStop := true
		for _, t := range ent.Tokens() {
			if !t.IsStop() {
				allStop = false
				break
			}
		}
		if allStop {
			continue
		}
		surface := cleanSurface(ent.Text())
		if len(surface) == 0 {
			continue
		}
		if m.stripNumeric {
			s := strings.TrimLeft(surface, "-+")
			s = strings.ReplaceAll(s, ".", "")
			if isDigitsOnly(s) {
				continue
			}
		}
		// Canonical: join token lemmas, lowercase
		lemmas := make([]string, 0)
		for _, t := range ent.Tokens() {
			if !t.IsPunct() && !t.IsSpace() {
				lemmas = append(lemmas, strings.ToLower(t.Lemma()))
			}
		}
		canonical := cleanSurface(strings.Join(lemmas, " "))
		if len(canonical) == 0 {
			continue
		}
		eid := autoID(canonical)
		if _, exists := found[eid]; !exists {
			found[eid] = &entryData{
				name:        canonical,
				displayName: surface,
				entityType:  strings.ToLower(ent.Label()),
			}
		}
		found[eid].spans = append(found[eid].spans, [2]int{ent.StartChar(), ent.EndChar()})
	}

	results := make([]EntityMatch, 0, len(found))
	for eid, info := range found {
		spans := info.spans
		sort.Slice(spans, func(i, j int) bool { return spans[i][0] < spans[j][0] })
		positions := make([]int, len(spans))
		for i, s := range spans {
			positions[i] = s[0]
		}
		results = append(results, EntityMatch{
			EntityID:    eid,
			Name:        info.name,
			DisplayName: info.displayName,
			EntityType:  info.entityType,
			Frequency:   len(spans),
			Positions:   positions,
			Spans:       spans,
		})
	}
	return results, nil
}

