func _isAcronym(word string) bool {
	letters := make([]rune, 0)
	for _, c := range word {
		if unicode.IsLetter(c) {
			letters = append(letters, c)
		}
	}
	if len(letters) < 2 {
		return false
	}
	for _, c := range letters {
		if !unicode.IsUpper(c) {
			return false
		}
	}
	return true
}

