// EntityNormalizer is a stateful normalizer with a configurable exceptions set.
type EntityNormalizer struct {
	exceptions map[string]struct{}
}

// NewEntityNormalizer constructs an EntityNormalizer merging global and extra exceptions.
func NewEntityNormalizer(extraExceptions map[string]struct{}) *EntityNormalizer {
	exc := make(map[string]struct{}, len(singularExceptions)+len(extraExceptions))
	for k := range singularExceptions {
		exc[k] = struct{}{}
	}
	for k := range extraExceptions {
		exc[k] = struct{}{}
	}
	return &EntityNormalizer{exceptions: exc}
}

// Normalize returns the canonical display form of entity, respecting the instance exception list.
func (n *EntityNormalizer) Normalize(entity string) string {
	if len(entity) == 0 {
		return ""
	}
	entity = strings.TrimSpace(entity)
	entity = leadingTrailingSymbolsRe.ReplaceAllString(entity, "")
	entity = strings.TrimSpace(entity)
	entity = multiSpaceRe.ReplaceAllString(entity, " ")
	if len(entity) == 0 {
		return ""
	}
	tokens, sep := _splitTokens(entity)
	filtered := make([]string, 0, len(tokens))
	for _, t := range tokens {
		if len(t) > 0 {
			filtered = append(filtered, t)
		}
	}
	if len(filtered) == 0 {
		return ""
	}
	last := filtered[len(filtered)-1]
	if !_isAcronym(last) {
		if _, inExc := n.exceptions[strings.ToLower(last)]; !inExc {
			engine, err := _getEngine()
			if err == nil {
				result, isSingular := engine.SingularNoun(last)
				if isSingular && len(result) > 0 {
					if len(last) > 0 && unicode.IsUpper(rune(last[0])) && !_isAcronym(last) {
						filtered[len(filtered)-1] = strings.Title(strings.ToLower(result))
					} else {
						filtered[len(filtered)-1] = result
					}
				}
			}
		}
	}
	return strings.Join(filtered, sep)
}

// CanonicalKey returns the lowercase normalized key for deduplication matching.
func (n *EntityNormalizer) CanonicalKey(entity string) string {
	return strings.ToLower(n.Normalize(entity))
}

