	schemaDirty      bool
	dataDirty        bool
}

// NewNerPipeline constructs a NerPipeline with the given options.
func NewNerPipeline(opts NerPipelineOptions) *NerPipeline {
	if opts.SpacyModel == "" {
		opts.SpacyModel = "en_core_web_sm"
	}
	if opts.MinSchemaTermLength == 0 {
		opts.MinSchemaTermLength = 2
	}
	return &NerPipeline{
		dbEnrich:         opts.DBEnrich,
		spacyEntities:    opts.SpacyEntities,
		spacyModel:       opts.SpacyModel,
		spacyEntityTypes: opts.SpacyEntityTypes,
		builder:          NewSchemaVocabBuilder(opts.MinSchemaTermLength),
	}
}

// _getSchemaMatcher returns a lazily-initialised SchemaMatcher.
// Rebuilds whenever the schema vocabulary has been dirtied since the last build.
func (p *NerPipeline) _getSchemaMatcher() *SchemaMatcher {
	if p.schemaMatcher == nil || p.schemaDirty {
		p.schemaMatcher = p.builder.Build()
		p.schemaDirty = false
	}
	return p.schemaMatcher
